import{_ as a,o as l,c as r,ag as e}from"./chunks/framework.DEqXEGcv.js";const b=JSON.parse('{"title":"文件管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/files.md","filePath":"zh/docs/guide/files.md"}'),i={name:"zh/docs/guide/files.md"};function o(d,t,n,s,h,u){return l(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="文件管理" tabindex="-1">文件管理 <a class="header-anchor" href="#文件管理" aria-label="Permalink to &quot;文件管理&quot;">​</a></h1><p>RDE 内置功能完整的文件管理器，在浏览器中提供桌面级的文件操作体验。</p><h2 id="基本操作" tabindex="-1">基本操作 <a class="header-anchor" href="#基本操作" aria-label="Permalink to &quot;基本操作&quot;">​</a></h2><ul><li><strong>浏览</strong>：树形目录导航，支持面包屑路径栏</li><li><strong>新建</strong>：创建文件、文件夹</li><li><strong>复制/剪切/粘贴</strong>：支持快捷键操作</li><li><strong>重命名</strong>：双击文件名或 F2 快捷键</li><li><strong>删除</strong>：支持回收站和直接删除</li><li><strong>搜索</strong>：按文件名搜索</li></ul><h2 id="文件上传" tabindex="-1">文件上传 <a class="header-anchor" href="#文件上传" aria-label="Permalink to &quot;文件上传&quot;">​</a></h2><p>支持多种上传方式：</p><ul><li><strong>拖拽上传</strong>：将文件拖拽到文件管理器窗口</li><li><strong>点击上传</strong>：通过上传按钮选择文件</li><li><strong>文件夹上传</strong>：支持整个文件夹上传</li></ul><h3 id="大文件断点续传" tabindex="-1">大文件断点续传 <a class="header-anchor" href="#大文件断点续传" aria-label="Permalink to &quot;大文件断点续传&quot;">​</a></h3><p>基于 TUS 协议实现断点续传，支持 10GB+ 大文件上传：</p><ul><li>网络中断自动恢复</li><li>显示上传进度</li><li>支持暂停/恢复</li></ul><h2 id="文件下载" tabindex="-1">文件下载 <a class="header-anchor" href="#文件下载" aria-label="Permalink to &quot;文件下载&quot;">​</a></h2><ul><li>单文件直接下载</li><li>多文件/文件夹打包为 ZIP 下载</li></ul><h2 id="文件预览" tabindex="-1">文件预览 <a class="header-anchor" href="#文件预览" aria-label="Permalink to &quot;文件预览&quot;">​</a></h2><p>内置多种文件预览器：</p><table tabindex="0"><thead><tr><th>类型</th><th>支持格式</th></tr></thead><tbody><tr><td>图片</td><td>JPG, PNG, GIF, SVG, WebP</td></tr><tr><td>视频</td><td>MP4, WebM, MKV</td></tr><tr><td>音频</td><td>MP3, FLAC, WAV, OGG</td></tr><tr><td>文档</td><td>TXT, Markdown, PDF</td></tr><tr><td>代码</td><td>支持语法高亮的代码查看器</td></tr></tbody></table><h2 id="文件分享" tabindex="-1">文件分享 <a class="header-anchor" href="#文件分享" aria-label="Permalink to &quot;文件分享&quot;">​</a></h2><p>支持生成分享链接，方便将文件分享给他人：</p><ul><li>设置分享密码（可选）</li><li>设置过期时间</li><li>支持限制下载次数</li></ul><h2 id="samba-共享" tabindex="-1">Samba 共享 <a class="header-anchor" href="#samba-共享" aria-label="Permalink to &quot;Samba 共享&quot;">​</a></h2><p>一键配置局域网文件共享服务，让其他设备通过 SMB 协议访问 RDE 上的文件。</p>',20)])])}const g=a(i,[["render",o]]);export{b as __pageData,g as default};
